import sys
import threading
from collections import defaultdict

def main():
    import sys
    sys.setrecursionlimit(1 << 25)
    N, M = map(int, sys.stdin.readline().split())
    graph = defaultdict(list)
    for _ in range(M):
        u, v = map(int, sys.stdin.readline().split())
        graph[u].append(v)
        graph[v].append(u)

    K = int(sys.stdin.readline())
    forbidden_pairs = set()
    for _ in range(K):
        x, y = map(int, sys.stdin.readline().split())
        if x > y:
            x, y = y, x
        forbidden_pairs.add((x, y))

    Q = int(sys.stdin.readline())
    queries = []
    for _ in range(Q):
        p, q = map(int, sys.stdin.readline().split())
        if p > q:
            p, q = q, p
        queries.append((p, q))

    # Union-Find (Disjoint Set Union)
    parent = list(range(N + 1))

    def find(u):
        while parent[u] != u:
            parent[u] = parent[parent[u]]
            u = parent[u]
        return u

    def union(u, v):
        pu = find(u)
        pv = find(v)
        if pu != pv:
            parent[pv] = pu

    # Build DSU
    for u in range(1, N + 1):
        for v in graph[u]:
            if find(u) != find(v):
                union(u, v)

    # Precompute for each node its root
    root = [find(i) for i in range(N + 1)]

    # For each forbidden pair, check if they are in the same component
    # We can precompute a set of forbidden roots
    forbidden_roots = set()
    for x, y in forbidden_pairs:
        if find(x) == find(y):
            # This should not happen as per problem statement
            pass
        else:
            forbidden_roots.add((find(x), find(y)))

    # Answer queries
    for p, q in queries:
        rp = find(p)
        rq = find(q)
        if (rp, rq) in forbidden_roots or (rq, rp) in forbidden_roots:
            print("No")
        else:
            print("Yes")

threading.Thread(target=main).start()
